mapper.select:
SELECT VENDOR_CODE as vendorCode, VENDOR_NAME as vendorName, MANAGER as manager, TEL as tel, EMAIL as email, MANAGER_TEL as managerTel, USER_COMPANY_CODE as userCompanyCode, STATUS as status, REG_DATE as regDate FROM MA_VENDOR WHERE 1 = 1
AND vendor_code LIKE CONCAT('%', #{vendorCode}, '%')
AND vendor_name LIKE CONCAT('%', #{vendorName}, '%')
and user_company_code = #{userCompanyCode}
and user_company_code IS NULL
and status = #{status}

SELECT VENDOR_CODE as vendorCode, VENDOR_NAME as vendorName, MANAGER as manager, TEL as tel, EMAIL as email, MANAGER_TEL as managerTel, USER_COMPANY_CODE as userCompanyCode, STATUS as status, REG_DATE as regDate FROM MA_VENDOR WHERE 1 = 1 AND vendor_code = #{vendorCode}
and user_company_code = #{userCompanyCode}
and user_company_code IS NULL
AND vendor_name = #{vendorName}

